sql:
SELECT COUNT(DISTINCT s.program_id) AS number_of_programs
FROM students s
JOIN programs p ON s.program_id = p.program_id;

SELECT AVG(program_count) AS average_students_per_program
FROM (
  SELECT program_id, COUNT(student_id) AS program_count
  FROM students
  GROUP BY program_id
);

SELECT COUNT(*) AS total_A_grades
FROM students_courses
WHERE grade = 'A';

external_knowledge:
- 'Blossoming scholars' refers to students who are performing well academically;
- 'Laurels of distinction' refers to grades of 'B' or 'A';
- '4-year academic voyage' refers to a 4-year academic program.

sql:
SELECT program_name
FROM programs
ORDER BY program_name;

SELECT COUNT(DISTINCT student_id) AS num_students
FROM (
  SELECT student_id FROM students_courses
  UNION
  SELECT president_id AS student_id FROM clubs
);

SELECT program_name
FROM programs
WHERE LENGTH(description) = (SELECT MAX(LENGTH(description)) FROM programs);

external_knowledge:
- GPA is calculated on a 4.0 scale where A+ to D- correspond to 4.0 to 1.0 respectively;
- The overall GPA is the average of the semester GPAs;
- A GPA of 3.5 is considered a high grade point average.
